import clsx from 'clsx';
import { motion, type Variants } from 'framer-motion';
import { useIntl } from 'react-intl';

import * as styles from './SuggestionTips.sty.js';
import { Flex } from '../../../layouts/flex/Flex.js';
import { Surface } from '../../../layouts/surface/Surface.js';
import { textStyle as textStyleCSS } from '../../../styles/textStyle.sty.js';
import { ExternalLink } from '../../../typography/external-link/ExternalLink.js';
import { Text } from '../../../typography/text/Text.js';
import { TextEllipsis } from '../../../typography/text-ellipsis/TextEllipsis.js';
import useOverlayTransition from '../hooks/useOverlayTransition.js';
import { filterFieldMessages } from '../messages.js';

// Animation variants for the SuggestionTips component
const suggestionTipsVariants: Variants = {
  enter: {
    // Compensate the parent scaling the content to 0.8
    scaleY: 1 / 0.85,
    opacity: 0,
  },
  default: {
    scaleY: 1,
    opacity: 1,
  },
  exit: {
    opacity: 0,
  },
};

/**
 * @public
 */
export const SuggestionTips = () => {
  const intl = useIntl();
  const transition = useOverlayTransition(true);

  const tips = [
    {
      shortcut: '⏎',
      text: intl.formatMessage(filterFieldMessages.suggestions.tips.apply),
    },
    {
      shortcut: '↓↑',
      text: intl.formatMessage(filterFieldMessages.suggestions.tips.selection),
    },
    {
      shortcut: 'esc',
      text: intl.formatMessage(filterFieldMessages.suggestions.tips.close),
    },
  ];

  return (
    <Surface
      className={styles.suggestionTips}
      paddingX={16}
      paddingY={8}
      elevation="floating"
    >
      <Flex
        as={motion.div}
        className={styles.suggestionTipsWrapper}
        columnGap={16}
        rowGap={8}
        justifyContent="space-between"
        flexWrap="wrap"
        variants={suggestionTipsVariants}
        initial="enter"
        animate="default"
        exit="exit"
        transition={transition}
      >
        <Flex
          className={styles.suggestionTipsContent}
          style={{ overflow: 'hidden' }}
          columnGap={16}
          rowGap={8}
        >
          {tips.map((tip) => {
            return (
              <Flex maxWidth="100%" gap={4} key={tip.shortcut + tip.text}>
                <Text textStyle="small-emphasized">{tip.shortcut} </Text>
                <TextEllipsis
                  className={clsx(
                    textStyleCSS({ textStyle: 'small' }),
                    styles.suggstionTipsEllipsis,
                  )}
                >
                  {tip.text}
                </TextEllipsis>
              </Flex>
            );
          })}
        </Flex>

        <ExternalLink
          href="https://docs.dynatrace.com/docs/get-started/dynatrace-ui/ui-filter-field"
          className={clsx(
            textStyleCSS({ textStyle: 'small' }),
            styles.docsLink,
          )}
          data-dt-name="FilterSyntax"
        >
          {intl.formatMessage(filterFieldMessages.docsLink)}
        </ExternalLink>
      </Flex>
    </Surface>
  );
};
